import type { CodegenConfig } from '@graphql-codegen/cli';

export enum Schema {
  Dev = 'https://cdn.graphql-hive.com/artifacts/v1/253c47dc-232e-47a6-9144-c951a44f2299/sdl.graphql',
  Prod = 'https://cdn.graphql-hive.com/artifacts/v1/b0a79696-1a48-4ba7-b4c9-7178f77d02cc/sdl.graphql',
}

const config = (schema: Schema = Schema.Dev): CodegenConfig => ({
  schema: {
    [schema]: {
      headers: {
        'X-Hive-CDN-Key':
          (schema === Schema.Prod ? process.env.HIVE_PROD_CDN_KEY : process.env.HIVE_DEV_CDN_KEY) ||
          '',
      },
    },
  },
  overwrite: true,
  hooks: {
    afterOneFileWrite: ['prettier --write'],
  },
  documents: [
    './src/**/*.graphql',
    './src/**/*.gql',
    './src/**/*.graphql.ts',
    './src/**/graphql/**/*.ts',
  ],
  generates: {
    'src/graphql/graphql.schema.ts': {
      plugins: ['typescript', 'typescript-operations', 'typescript-react-apollo'],
      config: {
        scalars: {
          MobileBigInt: 'number',
          Time: 'string',
          FixedLineDateTimeRFC3339: 'string',
        },
        reactApolloVersion: 3,
        withHooks: true,
        withHOC: false,
        withComponent: false,
      },
    },
    ...(schema === Schema.Dev && {
      'src/graphql/schema.graphql': {
        plugins: ['schema-ast'],
      },
    }),
  },
});

export default config(process.env.APP_ENV === 'production' ? Schema.Prod : Schema.Dev);
